"""2D Sine Wave + Fourier Transform DemonstrationThis script:1. Creates a 1D sine wave2. Converts it into a 2D image3. Computes the Fourier Transform (FFT)4. Displays both the original image and frequency spectrum"""import cv2from matplotlib import pyplot as pltimport numpy as np# ---------------------------------------------------# STEP 1: Generate a 1D sine wave# ---------------------------------------------------# Create x coordinates from 0 to 255x = np.arange(256)# Generate sine wave# Smaller denominator -> higher frequency -> denser stripesy = np.sin(2 * np.pi * x / 3)# Shift the sine wave upward# This avoids negative pixel valuesy += max(y)# ---------------------------------------------------# STEP 2: Convert sine wave into a 2D image# ---------------------------------------------------# Repeat the same sine wave across all rows# This creates vertical stripe patternsimg = np.array(    [[y[j] * 127 for j in range(256)] for i in range(256)],    dtype=np.uint8)# ---------------------------------------------------# STEP 3: Compute Fourier Transform# ---------------------------------------------------# Convert image to float32 before FFT# DFT_COMPLEX_OUTPUT returns:# channel 0 -> real part# channel 1 -> imaginary partdft = cv2.dft(    np.float32(img),    flags=cv2.DFT_COMPLEX_OUTPUT)# Move low frequencies to the centerdft_shift = np.fft.fftshift(dft)# Compute magnitude spectrum# magnitude = sqrt(real^2 + imaginary^2)magnitude_spectrum = 20 * np.log(    cv2.magnitude(        dft_shift[:, :, 0],        dft_shift[:, :, 1]    ) + 1)# ---------------------------------------------------# STEP 4: Display results# ---------------------------------------------------fig = plt.figure(figsize=(10, 10))# Show original imageax1 = fig.add_subplot(1, 2, 1)ax1.imshow(img, cmap="gray")ax1.set_title("Input Image")# Show FFT resultax2 = fig.add_subplot(1, 2, 2)ax2.imshow(magnitude_spectrum, cmap="gray")ax2.set_title("FFT Magnitude Spectrum")plt.show()